import React from 'react'
import { useContainerWidth, PersonBlock, Paragraph } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import { getSessionId } from '@fs/zion-session'
import { sgBaseUrl } from '@fs/zion-config'

const sgEnvUrl = sgBaseUrl || 'https://sg31b0.familysearch.org'

const profilePreviewWrapperMobile = css`
  width: 70%;
  margin: 0 auto;
`
const profilePreviewWrapper = css`
  width: 40%;
  margin: 0 auto;
`

const profilePreviewStyle = css`
  padding: 20px;
  border: 1px solid grey;
  width: 100%;
  border-radius: 4px;
  &[break='mobile'] {
    width: 100%;
  }
`

/**
 * ProfilePreview renders a preview of the user's public profile information
 * @returns {JSX.Element}
 * @constructor
 * @param {Object} userProfile object with profile information
 */

export default function ProfilePreview({ userProfile }) {
  const [t] = useTranslation()
  const atWidth = useContainerWidth()
  const screenSize = atWidth({ default: 'mobile', xl: 'tablet', xxl: 'desktop' })
  const isMobile = atWidth({ default: true, xs: false })

  return (
    <div>
      <Paragraph centered secondary>
        {t('profile-search.current-profile.label', 'How others see me in FamilySearch')}
      </Paragraph>
      <div className={isMobile ? profilePreviewWrapperMobile : profilePreviewWrapper}>
        <div className={profilePreviewStyle} break={screenSize}>
          <PersonBlock
            centered
            size="md"
            avatarSize="smaller"
            avatarProps={{
              src: `${sgEnvUrl}/service/msg-artifact/user-portrait/${
                userProfile.cisId
              }/thumb200s?sessionId=${getSessionId()}`,
              monogram: userProfile.name.value[0],
              size: atWidth({ default: 'md', sm: 'lg' }),
            }}
            name={userProfile.name.value}
            details={<Details userProfile={userProfile} />}
          />
        </div>
      </div>
    </div>
  )
}

function Details({ userProfile }) {
  const { t } = useTranslation()
  const countryName = userProfile?.location?.country?.name
  const countryIsPublic = userProfile?.location?.country?.visibility === 'PUBLIC'
  const stateOrProvinceName = userProfile?.location?.stateOrProvince?.name
  const stateIsPublic = userProfile?.location?.stateOrProvince?.visibility === 'PUBLIC'

  let locationSpan
  if (!countryIsPublic && !stateIsPublic) {
    locationSpan = t('profile-search.location-set-to-private', 'Location is set to private')
  }

  if (countryIsPublic && !stateIsPublic) {
    locationSpan = countryName
  }

  if (stateIsPublic && countryIsPublic) {
    locationSpan = `${stateOrProvinceName}, ${countryName}`
  }

  if (!countryName && !stateOrProvinceName) {
    locationSpan = t('profile-search.location-not-added', 'Location not added')
  }
  return (
    <>
      <span>{userProfile.contactId.value}</span>
      <br />
      <span>{locationSpan}</span>
    </>
  )
}
